// Merge Tavily + SerpApi results, deduplicate by URL
const queryText = $('Query Webhook').first().json.body.query_text;
const queryId = $('Query Webhook').first().json.body.query_id;

const results = [];
const seenUrls = new Set();

// Process Tavily results
try {
  const tavily = $('Tavily Search').first().json;
  const tavilyResults = tavily.body?.results || tavily.results || [];
  for (const r of tavilyResults) {
    const url = (r.url || '').trim();
    if (!url || seenUrls.has(url)) continue;
    seenUrls.add(url);
    results.push({
      title: (r.title || '').trim(),
      url,
      content: (r.content || '').substring(0, 500),
      source: 'tavily',
      score: r.score || 0,
      published_date: r.published_date || ''
    });
  }
} catch (e) { /* Tavily failed, continue with SerpApi */ }

// Process SerpApi results
try {
  const serp = $('SerpApi Search').first().json;
  const organicResults = serp.body?.organic_results || serp.organic_results || [];
  for (const r of organicResults) {
    const url = (r.link || '').trim();
    if (!url || seenUrls.has(url)) continue;
    seenUrls.add(url);
    results.push({
      title: (r.title || '').trim(),
      url,
      content: (r.snippet || '').substring(0, 500),
      source: 'serpapi',
      score: r.position ? (1 - (r.position - 1) * 0.15) : 0.5,
      published_date: r.date || ''
    });
  }
} catch (e) { /* SerpApi failed, continue */ }

// Sort by score descending, take top 8
results.sort((a, b) => b.score - a.score);
const top = results.slice(0, 8);

return [{
  json: {
    query_text: queryText,
    query_id: queryId,
    web_results: top,
    result_count: top.length
  }
}];
